Here are the public test cases for feature10_reject_null_string_data:
{
  "description": "Storing a text value verbatim rejects a null payload. The rejection is reported as a normalized argument error that names the offending data parameter, and nothing is stored.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set_string",
            "key": "MyValue",
            "value": null
          }
        ]
      },
      "expected_output": "error=argument_null param=data\n"
    }
  ]
}

Here are the public test cases for feature11_1_change_events_on_save:
{
  "description": "Saving a value under a new key raises two notifications in order: a pre-save 'changing' notification and a post-save 'changed' notification. Both report the key, an empty (null) previous value, and the new value; the pre-save notification additionally exposes a not-cancelled flag.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "track_events": true,
        "steps": [
          {
            "op": "set",
            "key": "Key",
            "type": "string",
            "value": "Data"
          }
        ]
      },
      "expected_output": "event=changing key=Key old=<null> new=Data cancel=false\nevent=changed key=Key old=<null> new=Data\n"
    }
  ]
}

Here are the public test cases for feature11_2_cancel_changing:
{
  "description": "If a subscriber marks the pre-save 'changing' notification as cancelled, the write is abandoned: the value is not stored (the count stays zero) and no post-save 'changed' notification is raised.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "track_events": true,
        "cancel_changing": true,
        "steps": [
          {
            "op": "set",
            "key": "Key",
            "type": "string",
            "value": "Data"
          },
          {
            "op": "length"
          }
        ]
      },
      "expected_output": "event=changing key=Key old=<null> new=Data cancel=true\nlength=0\n"
    }
  ]
}

Here are the public test cases for feature11_3_change_events_old_value_on_update:
{
  "description": "When a save overwrites a key that already held a value, both the pre-save and post-save notifications report the previously stored value as the old value and the incoming value as the new value.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "track_events": true,
        "preset": [
          {
            "key": "Key",
            "raw": "Foo"
          }
        ],
        "steps": [
          {
            "op": "set",
            "key": "Key",
            "type": "string",
            "value": "Data"
          }
        ]
      },
      "expected_output": "event=changing key=Key old=Foo new=Data cancel=false\nevent=changed key=Key old=Foo new=Data\n"
    }
  ]
}

Here are the public test cases for feature1_1_primitive_roundtrip:
{
  "description": "Store a primitive value (text or number) under a key, then read the current item count and read the value back. The retrieved value round-trips to the same primitive that was stored, and the store reports exactly one item.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set",
            "key": "testKey",
            "type": "string",
            "value": "stringTest"
          },
          {
            "op": "length"
          },
          {
            "op": "get",
            "key": "testKey",
            "type": "string"
          }
        ]
      },
      "expected_output": "length=1\nvalue=stringTest\n"
    },
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set",
            "key": "k",
            "type": "int",
            "value": 11
          },
          {
            "op": "length"
          },
          {
            "op": "get",
            "key": "k",
            "type": "int"
          }
        ]
      },
      "expected_output": "length=1\nvalue=11\n"
    }
  ]
}

Here are the public test cases for feature1_2_object_roundtrip:
{
  "description": "Store a structured object (here a record with an integer id and a name) under a key, then read the item count and read the object back. Its fields round-trip unchanged, serialized as a JSON object.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set",
            "key": "testKey",
            "type": "object",
            "value": {
              "Id": 2,
              "Name": "Jane Smith"
            }
          },
          {
            "op": "length"
          },
          {
            "op": "get",
            "key": "testKey",
            "type": "object"
          }
        ]
      },
      "expected_output": "length=1\nvalue={\"Id\":2,\"Name\":\"Jane Smith\"}\n"
    }
  ]
}

