Here are the public test cases for feature1_4_overwrite_value:
{
  "description": "Store a value under a key and then store a different value under the same key. The latest write replaces the earlier one, so reading the key returns the most recently stored value.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set",
            "key": "k",
            "type": "string",
            "value": "first-value"
          },
          {
            "op": "set",
            "key": "k",
            "type": "string",
            "value": "second-value"
          },
          {
            "op": "get",
            "key": "k",
            "type": "string"
          }
        ]
      },
      "expected_output": "value=second-value\n"
    }
  ]
}

Here are the public test cases for feature2_1_read_as_raw_string:
{
  "description": "Store a typed value, then read it back as its raw stored text. The result is the exact serialized form held in the store: text values keep their surrounding JSON quotes, numbers are their digits, and objects are a JSON object string.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set",
            "key": "k",
            "type": "int",
            "value": 11
          },
          {
            "op": "get_string",
            "key": "k"
          }
        ]
      },
      "expected_output": "raw=11\n"
    },
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set",
            "key": "k",
            "type": "object",
            "value": {
              "Id": 2,
              "Name": "Jane Smith"
            }
          },
          {
            "op": "get_string",
            "key": "k"
          }
        ]
      },
      "expected_output": "raw={\"Id\":2,\"Name\":\"Jane Smith\"}\n"
    }
  ]
}

Here are the public test cases for feature2_2_backward_compat_raw_string:
{
  "description": "When the stored content for a key is not valid serialized JSON, requesting that key as a text value returns the original raw stored text unchanged instead of failing.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "preset": [
          {
            "key": "k",
            "raw": "[{ id: 5, name: \"Jane Smith\"}]"
          }
        ],
        "steps": [
          {
            "op": "get",
            "key": "k",
            "type": "string"
          }
        ]
      },
      "expected_output": "value=[{ id: 5, name: \"Jane Smith\"}]\n"
    }
  ]
}

