Here are the public test cases for feature4_remove_item:
{
  "description": "Remove a key from the store. Removing a key that exists deletes it (the count drops). Removing a key that is not present is a no-op and leaves the store unchanged.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set",
            "key": "testKey",
            "type": "object",
            "value": {
              "Id": 2,
              "Name": "Jane Smith"
            }
          },
          {
            "op": "length"
          },
          {
            "op": "remove",
            "key": "testKey"
          },
          {
            "op": "length"
          }
        ]
      },
      "expected_output": "length=1\nlength=0\n"
    },
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "remove",
            "key": "testKey"
          },
          {
            "op": "length"
          }
        ]
      },
      "expected_output": "length=0\n"
    }
  ]
}

Here are the public test cases for feature5_clear_store:
{
  "description": "Clear the whole store. Clearing a populated store removes every entry (the count becomes zero). Clearing an already-empty store is a no-op.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set",
            "key": "Item1",
            "type": "object",
            "value": {
              "Id": 1,
              "Name": "Jane Smith"
            }
          },
          {
            "op": "set",
            "key": "Item2",
            "type": "object",
            "value": {
              "Id": 2,
              "Name": "John Smith"
            }
          },
          {
            "op": "length"
          },
          {
            "op": "clear"
          },
          {
            "op": "length"
          }
        ]
      },
      "expected_output": "length=2\nlength=0\n"
    },
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "clear"
          },
          {
            "op": "length"
          }
        ]
      },
      "expected_output": "length=0\n"
    }
  ]
}

