Here are the public test cases for feature7_key_by_index:
{
  "description": "Look up the name of the key stored at a given zero-based insertion position. A valid position returns that key's name; a position beyond the last entry returns null.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set",
            "key": "TestKey1",
            "type": "object",
            "value": {
              "Id": 1,
              "Name": "Jane Smith"
            }
          },
          {
            "op": "set",
            "key": "TestKey2",
            "type": "object",
            "value": {
              "Id": 2,
              "Name": "John Smith"
            }
          },
          {
            "op": "key",
            "index": 1
          }
        ]
      },
      "expected_output": "key=TestKey2\n"
    },
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set",
            "key": "TestKey1",
            "type": "object",
            "value": {
              "Id": 1,
              "Name": "Jane Smith"
            }
          },
          {
            "op": "key",
            "index": 1
          }
        ]
      },
      "expected_output": "key=<null>\n"
    }
  ]
}

Here are the public test cases for feature8_key_exists:
{
  "description": "Check whether a key currently exists in the store. The answer is true when a value has been stored under that key and false otherwise.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set",
            "key": "TestKey",
            "type": "object",
            "value": {
              "Id": 1,
              "Name": "Jane Smith"
            }
          },
          {
            "op": "contains",
            "key": "TestKey"
          }
        ]
      },
      "expected_output": "contains=true\n"
    },
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "contains",
            "key": "TestKey"
          }
        ]
      },
      "expected_output": "contains=false\n"
    }
  ]
}

Here are the public test cases for feature9_reject_invalid_key:
{
  "description": "Every keyed operation rejects a key that is null, empty, or whitespace-only. The rejection is reported as a normalized argument error that names the offending key parameter, and no operation is performed.",
  "cases": [
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set",
            "key": "",
            "type": "string",
            "value": "Data"
          }
        ]
      },
      "expected_output": "error=argument_null param=key\n"
    },
    {
      "input": {
        "mode": "sync",
        "steps": [
          {
            "op": "set",
            "key": null,
            "type": "string",
            "value": "Data"
          }
        ]
      },
      "expected_output": "error=argument_null param=key\n"
    }
  ]
}
